SELECT sku, path FROM products WHERE brand='Makita' AND name='Workshop Drill Grinder and Sander' AND series='Makita Workshop DHS 2Z9-X7O Workshop Drill Grinder and Sander line' AND json_extract(properties,'$.machine_type')='lathe' LIMIT 10;
SELECT id, path, name, city FROM stores WHERE city='Vienna' ORDER BY id;
SELECT s.id, s.path, COALESCE(i.available_today,0) AS available_today FROM stores s LEFT JOIN inventory i ON i.store_id=s.id AND i.sku=(SELECT sku FROM products WHERE brand='Makita' AND name='Workshop Drill Grinder and Sander' AND series='Makita Workshop DHS 2Z9-X7O Workshop Drill Grinder and Sander line' AND json_extract(properties,'$.machine_type')='lathe' LIMIT 1) WHERE s.city='Vienna' ORDER BY s.id;
